import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators, AbstractControl } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  loading = false;
  error = '';
  showPassword = false;
  roles = ['General User', 'Admin'];

  constructor(
    private fb: FormBuilder,
    private auth: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) {
      this.router.navigate(['/dashboard']);
      return;
    }
    this.loginForm = this.fb.group({
      userId:   ['', [Validators.required]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      role:     ['General User', Validators.required]
    });
  }

  // Individual getters — no index signature, no TS4111
  get userId(): AbstractControl { return this.loginForm.get('userId')!; }
  get password(): AbstractControl { return this.loginForm.get('password')!; }
  get role(): AbstractControl { return this.loginForm.get('role')!; }

  onSubmit(): void {
    if (this.loginForm.invalid) {
      this.loginForm.markAllAsTouched();
      return;
    }
    this.loading = true;
    this.error = '';
    const { userId, password, role } = this.loginForm.value;

    this.auth.login(userId, password, role).subscribe({
      next: (res: any) => {
        this.loading = false;
        if (res.success) this.router.navigate(['/dashboard']);
      },
      error: (err: any) => {
        this.loading = false;
        this.error = err.error?.message || 'Login failed. Please try again.';
      }
    });
  }
}
<div class="login-page">
  <div class="login-left">
    <div class="brand">
      <div class="brand-logo">M</div>
      <div class="brand-text">
        <h1>MPloyChek</h1>
        <p>by NSQTech Private Limited</p>
      </div>
    </div>
    <div class="tagline">
      <h2>Digital Background<br/>Verification Platform</h2>
      <p>Secure, fast, and reliable candidate verification for modern enterprises.</p>
    </div>
    <div class="features">
      <div class="feature-item"><span class="icon">✓</span> Real-time verification status</div>
      <div class="feature-item"><span class="icon">✓</span> Role-based access control</div>
      <div class="feature-item"><span class="icon">✓</span> Multi-level record management</div>
    </div>
  </div>

  <div class="login-right">
    <div class="login-card">
      <div class="login-header">
        <h2>Welcome back</h2>
        <p>Sign in to your account to continue</p>
      </div>

      <div class="demo-creds">
        <div class="cred-label">Demo credentials</div>
        <div class="cred-row"><b>Admin:</b> ADM001 / admin123</div>
        <div class="cred-row"><b>User:</b> USR001 / password123</div>
      </div>

      <form [formGroup]="loginForm" (ngSubmit)="onSubmit()">

        <div class="form-group" [class.error]="userId.touched && userId.invalid">
          <label>User ID</label>
          <div class="input-wrap">
            <span class="input-icon">👤</span>
            <input type="text" formControlName="userId" placeholder="Enter your user ID" autocomplete="username"/>
          </div>
          <span class="err-msg" *ngIf="userId.touched && userId.hasError('required')">User ID is required</span>
        </div>

        <div class="form-group" [class.error]="password.touched && password.invalid">
          <label>Password</label>
          <div class="input-wrap">
            <span class="input-icon">🔒</span>
            <input [type]="showPassword ? 'text' : 'password'" formControlName="password" placeholder="Enter your password" autocomplete="current-password"/>
            <button type="button" class="toggle-pw" (click)="showPassword = !showPassword">{{ showPassword ? '🙈' : '👁️' }}</button>
          </div>
          <span class="err-msg" *ngIf="password.touched && password.hasError('required')">Password is required</span>
          <span class="err-msg" *ngIf="password.touched && password.hasError('minlength')">Minimum 6 characters</span>
        </div>

        <div class="form-group">
          <label>Role</label>
          <div class="role-selector">
            <label class="role-option" *ngFor="let r of roles" [class.active]="loginForm.get('role')?.value === r">
              <input type="radio" formControlName="role" [value]="r" hidden/>
              <span class="role-icon">{{ r === 'Admin' ? '🛡️' : '👤' }}</span>
              <span>{{ r }}</span>
            </label>
          </div>
        </div>

        <div class="alert-error" *ngIf="error">{{ error }}</div>

        <button type="submit" class="btn-login" [disabled]="loading">
          <span *ngIf="!loading">Sign In →</span>
          <span *ngIf="loading" class="spinner"></span>
        </button>

      </form>
    </div>
  </div>
</div>
